SELECT u.username, d.name AS department, COUNT(o.id) AS orders
FROM users u
LEFT JOIN departments d ON u.department_id = d.id
LEFT JOIN orders o ON u.id = o.user_id
WHERE u.age >= 21
GROUP BY u.username, d.name
HAVING COUNT(o.id) > 0
ORDER BY orders DESC
LIMIT 10;

