-- Transaction A                     -- Transaction B
-- SET ISOLATION READ UNCOMMITTED;
-- BEGIN;                            -- BEGIN;
--                                   -- UPDATE accounts SET balance = 0
--                                   --   WHERE id = 1;  (not committed!)
-- SELECT balance FROM accounts
--   WHERE id = 1;
-- -> Returns 0 (DIRTY READ!)
--                                   -- ROLLBACK;  (change undone)
