-- Transaction A (READ_COMMITTED)     -- Transaction B
-- BEGIN;
-- SELECT balance FROM accounts
--   WHERE id = 1;  -> 1000
--                                   -- BEGIN;
--                                   -- UPDATE accounts SET balance = 500
--                                   --   WHERE id = 1;
--                                   -- COMMIT;
-- SELECT balance FROM accounts
--   WHERE id = 1;  -> 500 (DIFFERENT!)
-- Two reads, different results = non-repeatable read

